func newAuthStatusCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "status",
		Short:   "Show authentication status",
		Example: "  anylist-pp-cli auth status",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			w := cmd.OutOrStdout()
			header := cfg.AuthHeader()
			authed := header != ""
			// JSON envelope: {authenticated, verified, source, config}. When not
			// authenticated, write the envelope first then return authErr
			// so exit code carries the auth-failure signal.
			if flags.asJSON {
				out := map[string]any{
					"authenticated": authed,
					"verified":      false,
					"source":        cfg.AuthSource,
					"config":        cfg.Path,
				}
				if printErr := printJSONFiltered(w, out, flags); printErr != nil {
					return printErr
				}
				if !authed {
					return authErr(fmt.Errorf("no credentials configured"))
				}
				return nil
			}
			if !authed {
				fmt.Fprintln(w, red("Not authenticated"))
				fmt.Fprintln(w, "")
				fmt.Fprintln(w, "Set your token:")
				fmt.Fprintln(w, "  export ANYLIST_ACCESS_TOKEN=\"your-token-here\"")
				fmt.Fprintf(w, "  anylist-pp-cli auth set-token <token>\n")
				return authErr(fmt.Errorf("no credentials configured"))
			}

			fmt.Fprintln(w, green("Credentials present (not verified)"))
			fmt.Fprintf(w, "  Source: %s\n", cfg.AuthSource)
			fmt.Fprintf(w, "  Config: %s\n", cfg.Path)
			return nil
		},
	}
}

func newAuthSetTokenCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "set-token <token>",
		Short:   "Save an API token to the config file",
		Example: "  anylist-pp-cli auth set-token YOUR_TOKEN_HERE",
		Args:    cobra.ExactArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			// Clear any legacy auth_header so AuthHeader() falls through to
			// the newly-saved credential. Without this, a pre-existing
			// auth_header value (common after regenerate) shadows the saved
			// token and set-token silently has no effect. Silent clear (no
			// log line): a masked-tail variant could leak token bytes through
			// scripted dogfood that captures stderr.
			cfg.AuthHeaderVal = ""
			if err := cfg.SaveTokens("", "", args[0], "", cfg.TokenExpiry); err != nil {
				return configErr(fmt.Errorf("saving token: %w", err))
			}

			// JSON envelope: {saved, config_path}.
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"saved":       true,
					"config_path": cfg.Path,
				}, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Token saved to %s\n", cfg.Path)
			return nil
		},
	}
}

func newAuthLogoutCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "logout",
		Short:   "Clear stored credentials",
		Example: "  anylist-pp-cli auth logout",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			if err := cfg.ClearTokens(); err != nil {
				return configErr(fmt.Errorf("clearing tokens: %w", err))
			}

			// Identify which (if any) auth env var is still exported so the
			// JSON envelope and the human prose can both surface it.
			envStillSet := ""
			if envStillSet == "" && os.Getenv("ANYLIST_ACCESS_TOKEN") != "" {
				envStillSet = "ANYLIST_ACCESS_TOKEN"
			}

			// JSON envelope: {cleared: true, note?: "<env_var> env var is still set"}.
			if flags.asJSON {
				out := map[string]any{"cleared": true}
				if envStillSet != "" {
					out["note"] = envStillSet + " env var is still set"
				}
				return printJSONFiltered(cmd.OutOrStdout(), out, flags)
			}

			if envStillSet != "" {
				fmt.Fprintf(cmd.OutOrStdout(), "Config cleared. Note: %s env var is still set.\n", envStillSet)
				return nil
			}
			fmt.Fprintln(cmd.OutOrStdout(), "Logged out. Credentials cleared.")
			return nil
		},
	}
}

func newAuthLoginCmd(flags *rootFlags) *cobra.Command {
	var email string
	var password string

	cmd := &cobra.Command{
		Use:     "login",
		Short:   "Authenticate with email and password",
		Example: "  anylist-pp-cli auth login --email you@example.com",
		RunE: func(cmd *cobra.Command, args []string) error {
			ctx := cmd.Context()

			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			if email == "" {
				if flags.noInput {
					return usageErr(fmt.Errorf("--email is required (--no-input mode)"))
				}
				fmt.Fprint(os.Stderr, "Email: ")
				scanner := bufio.NewScanner(os.Stdin)
				if scanner.Scan() {
					email = strings.TrimSpace(scanner.Text())
				}
				if email == "" {
					return usageErr(fmt.Errorf("email is required"))
				}
			}

			if password == "" {
				if flags.noInput {
					return usageErr(fmt.Errorf("password is required (--no-input mode)"))
				}
				fmt.Fprint(os.Stderr, "Password: ")
				if stdinIsTerminal(int(syscall.Stdin)) {
					pwBytes, err := readTerminalPassword(int(syscall.Stdin))
					fmt.Fprintln(os.Stderr)
					if err != nil {
						// PATCH: Do not degrade terminal password reads to echoed plaintext.
						return fmt.Errorf("reading password: %w", err)
					}
					password = string(pwBytes)
				} else {
					scanner := bufio.NewScanner(os.Stdin)
					if scanner.Scan() {
						password = strings.TrimSpace(scanner.Text())
					}
				}
				if password == "" {
					return usageErr(fmt.Errorf("password is required"))
				}
			}

			alClient := anylist.New(cfg)
			if err := alClient.Login(ctx, email, password); err != nil {
				return fmt.Errorf("login failed: %w", err)
			}

			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"logged_in": true,
					"user_id":   cfg.UserID,
				}, flags)
			}
			fmt.Fprintln(cmd.OutOrStdout(), "Logged in successfully. Run 'anylist-pp-cli sync' to populate local cache.")
			return nil
		},
	}

	cmd.Flags().StringVar(&email, "email", "", "AnyList account email")
	return cmd
}

